//! Mycelial Cache Router: Fano 7 Geometry + Dynkin Tiers
//!
//! Implements the formal mycelial cache diversity theorem in runtime:
//! 5 tier types (E3-E8) × Fano 7 incidence (3 lines/point) → zero cache deficit.
//!
//! Query hash → Fano 7 point → 3 incident lines → 3 tier hits → coherent eviction.

use std::collections::HashMap;
use std::sync::atomic::{AtomicU64, Ordering};

/// Fano 7 point (0..6)
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
pub struct FanoPoint(u8);

impl FanoPoint {
    pub fn new(index: u8) -> Self {
        FanoPoint(index % 7)
    }

    pub fn as_u8(&self) -> u8 {
        self.0
    }
}

/// Fano 7 line (0..6)
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct FanoLine(u8);

impl FanoLine {
    pub fn new(index: u8) -> Self {
        FanoLine(index % 7)
    }

    pub fn as_u8(&self) -> u8 {
        self.0
    }
}

/// Fano incidence: point on line
/// Hardcoded Fano plane incidence matrix
pub fn fano_incidence(p: FanoPoint, l: FanoLine) -> bool {
    match (l.as_u8(), p.as_u8()) {
        (0, 0) | (0, 1) | (0, 3) => true,
        (1, 1) | (1, 2) | (1, 4) => true,
        (2, 2) | (2, 3) | (2, 5) => true,
        (3, 3) | (3, 4) | (3, 6) => true,
        (4, 4) | (4, 5) | (4, 0) => true,
        (5, 5) | (5, 6) | (5, 1) => true,
        (6, 6) | (6, 0) | (6, 2) => true,
        _ => false,
    }
}

/// Lines through a point
pub fn point_lines(p: FanoPoint) -> Vec<FanoLine> {
    (0..7)
        .filter(|&i| fano_incidence(p, FanoLine(i)))
        .map(FanoLine)
        .collect()
}

/// Points on a line
pub fn line_points(l: FanoLine) -> Vec<FanoPoint> {
    (0..7)
        .filter(|&i| fano_incidence(FanoPoint(i), l))
        .map(FanoPoint)
        .collect()
}

/// Cache tier enumeration
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
pub enum CacheTier {
    E3 = 3,
    E4 = 4,
    E5 = 5,
    E6 = 6,
    E8 = 8,
}

impl CacheTier {
    /// Tier coverage: which Fano points this tier owns
    pub fn coverage(&self) -> Vec<FanoPoint> {
        match self {
            CacheTier::E3 => (0..3).map(FanoPoint).collect(),
            CacheTier::E4 => (0..4).map(FanoPoint).collect(),
            CacheTier::E5 => (0..5).map(FanoPoint).collect(),
            CacheTier::E6 => (0..6).map(FanoPoint).collect(),
            CacheTier::E8 => (0..7).map(FanoPoint).collect(),
        }
    }

    /// Capacity (latent keys)
    pub fn capacity(&self) -> u64 {
        match self {
            CacheTier::E3 => 48,
            CacheTier::E4 => 100,
            CacheTier::E5 => 320,
            CacheTier::E6 => 4_320,
            CacheTier::E8 => 696_729_600,
        }
    }
}

/// Mycelial Fano Router: dispatches queries to tier coherence groups
#[derive(Debug)]
pub struct MycelialFanoRouter {
    /// Line → primary tier assignment (round-robin)
    line_to_tier: HashMap<FanoLine, CacheTier>,
}

impl Default for MycelialFanoRouter {
    fn default() -> Self {
        Self::new()
    }
}

impl MycelialFanoRouter {
    pub fn new() -> Self {
        let mut line_to_tier = HashMap::new();
        for i in 0..7 {
            let tier = match i % 5 {
                0 => CacheTier::E8,
                1 => CacheTier::E6,
                2 => CacheTier::E5,
                3 => CacheTier::E4,
                _ => CacheTier::E3,
            };
            line_to_tier.insert(FanoLine(i as u8), tier);
        }
        MycelialFanoRouter { line_to_tier }
    }

    /// Query routing: hash → Fano point → incident lines → tiers
    ///
    /// The hash reduces by `% 7`, which LLVM strength-reduces to multiply-
    /// shift. The certified division-free fold
    /// (`foil_mersenne_hot_path::fano_point_of_hash`, Lean: `fano_mod7_fold`)
    /// is the measured-equivalent alternative for multiplier-saturated ports;
    /// on an idle multiplier the compiler variant won the A/B (~2 ns vs ~17 ns
    /// per reduction), so the plan's acceptance rule keeps `% 7` here.
    pub fn route_query(&self, query_hash: u64) -> Vec<CacheTier> {
        let fano_point = FanoPoint::new((query_hash % 7) as u8);
        let lines = point_lines(fano_point);

        let mut tiers = Vec::new();
        for line in lines {
            if let Some(&tier) = self.line_to_tier.get(&line) {
                tiers.push(tier);
            }
        }
        // Deduplicate
        tiers.sort_unstable();
        tiers.dedup();
        tiers
    }

    /// **VentInterferePast-weighted discharge** — the closing edge of the
    /// mycelial loop.
    ///
    /// Like [`route_query`], the query hash selects a Fano point and its 3
    /// incident lines (the zero-deficit cover). But instead of discharging
    /// `count` predicted keys uniformly, we apportion them across the 3 lines
    /// **proportional to each line's realized hit weight** ([`fano_line_weight`],
    /// the Laplace-smoothed `hits/admitted` updated by the backward vent). A line
    /// that keeps paying off pulls more forecast mass toward itself — Hotelling
    /// repositioning toward demand — while every incident line keeps at least one
    /// share so the 3-line cover (zero deficit) is preserved no matter how far the
    /// routing skews.
    ///
    /// Returns `(line, tier, share)` with `share`s summing to `count`. Lean:
    /// `MycelialMeshAttentionHotelling.mediant_moves_toward_dominant_line`.
    pub fn weighted_discharge_plan(
        &self,
        query_hash: u64,
        count: usize,
    ) -> Vec<(FanoLine, CacheTier, usize)> {
        let point = FanoPoint::new((query_hash % 7) as u8);
        let lines = point_lines(point); // Fano axiom: exactly 3
        let n = lines.len();
        if n == 0 || count == 0 {
            return Vec::new();
        }

        // Reserve one share per incident line first (zero-deficit cover), then
        // apportion the remainder by realized hit weight (largest remainder).
        let mut shares = vec![0usize; n];
        let reserve = n.min(count);
        for share in shares.iter_mut().take(reserve) {
            *share = 1;
        }
        let remaining = count - reserve;

        if remaining > 0 {
            let weights: Vec<f64> = lines
                .iter()
                .map(|line| {
                    let (num, den) = fano_line_weight(*line);
                    num as f64 / den as f64
                })
                .collect();
            let wsum: f64 = weights.iter().sum();
            if wsum > 0.0 {
                // One-at-a-time largest-remainder apportionment: hand each of the
                // `remaining` units to the line currently furthest below its
                // weighted ideal. This sums to exactly `remaining` by
                // construction (one unit handed out per iteration), with no f64
                // round/underflow risk, and steers mass toward the heaviest
                // line (Hotelling reposition). `n` is always 3, so this is O(n).
                let ideal: Vec<f64> = weights.iter().map(|w| w / wsum).collect();
                let mut extra = vec![0usize; n];
                for unit in 0..remaining {
                    let mut best = 0usize;
                    let mut best_score = f64::NEG_INFINITY;
                    for i in 0..n {
                        let score = ideal[i] * (unit as f64 + 1.0) - extra[i] as f64;
                        if score > best_score {
                            best_score = score;
                            best = i;
                        }
                    }
                    extra[best] += 1;
                }
                for i in 0..n {
                    shares[i] += extra[i];
                }
            }
        }

        lines
            .into_iter()
            .enumerate()
            .map(|(i, line)| {
                let tier = self.line_to_tier.get(&line).copied().unwrap_or(CacheTier::E8);
                (line, tier, shares[i])
            })
            .collect()
    }

    /// Eviction priority: distance-based on Fano geometry
    pub fn eviction_priority(query_point: FanoPoint, cached_point: FanoPoint) -> u32 {
        if query_point == cached_point {
            3 // Self: keep
        } else if Self::collinear(query_point, cached_point) {
            2 // Collinear: medium priority
        } else {
            0 // Pole/dual: eviction candidate
        }
    }

    fn collinear(p: FanoPoint, q: FanoPoint) -> bool {
        point_lines(p).iter().any(|&l| fano_incidence(q, l))
    }
}

// ─── VentInterferePast feedback: the backward edge of the mycelial loop ──────
//
// Per Fano line, two process-global counters: predicted keys `admitted` (the
// forward fork) and keys later `hit` (the backward vent — a confirmed
// Wheeler–Feynman handshake). They are global, like the FOIL entropy atomics in
// `gnosis_foil`, so the forward discharge and the backward vent share one loop
// across every `FoilRuntimeConfig` instance. A line's realized hit weight feeds
// `weighted_discharge_plan`, so the loop steers future forecasts toward the
// lines that pay — converging to the Hotelling / mycelial-mesh-attention
// equilibrium. Lean: `MycelialMeshAttentionHotelling`.

const FANO_LINES: usize = 7;

#[allow(clippy::declare_interior_mutable_const)]
const ZERO_U64: AtomicU64 = AtomicU64::new(0);
static LINE_ADMITTED: [AtomicU64; FANO_LINES] = [ZERO_U64; FANO_LINES];
static LINE_HITS: [AtomicU64; FANO_LINES] = [ZERO_U64; FANO_LINES];

/// Provenance: the low 3 bits of a predicted key carry its source Fano line
/// (0..6), so a later hit can be credited to the line that forecast it without a
/// side map — the tag rides the key through the async loser queue.
pub const FANO_LINE_TAG_MASK: u64 = 0b111;

/// Stamp `key`'s low 3 bits with its source `line` so the hit path can recover
/// the forecasting line. The keys are synthetic cache identities, so spending 3
/// low bits on provenance is free.
pub fn tag_key_with_line(key: u64, line: FanoLine) -> u64 {
    (key & !FANO_LINE_TAG_MASK) | (line.as_u8() as u64 & FANO_LINE_TAG_MASK)
}

/// Recover the source Fano line stamped into a predicted key by
/// [`tag_key_with_line`]. Only meaningful on keys we tagged on the forward path.
pub fn line_from_key(key: u64) -> FanoLine {
    FanoLine::new((key & FANO_LINE_TAG_MASK) as u8)
}

/// Forward fork accounting: a predicted key forecast by `line` was admitted to
/// the loser cache.
pub fn fano_line_record_admit(line: FanoLine) {
    LINE_ADMITTED[line.as_u8() as usize].fetch_add(1, Ordering::Relaxed);
}

/// **VentInterferePast**: a predicted key forecast by `line` was actually hit —
/// a confirmed handshake. This is the backward edge that closes the loop.
pub fn fano_line_credit_hit(line: FanoLine) {
    LINE_HITS[line.as_u8() as usize].fetch_add(1, Ordering::Relaxed);
}

/// Keys forecast by `line` that were admitted to the cache.
pub fn fano_line_admitted(line: FanoLine) -> u64 {
    LINE_ADMITTED[line.as_u8() as usize].load(Ordering::Relaxed)
}

/// Keys forecast by `line` that were later hit.
pub fn fano_line_hits(line: FanoLine) -> u64 {
    LINE_HITS[line.as_u8() as usize].load(Ordering::Relaxed)
}

/// Laplace-smoothed realized hit weight of a line as a `(num, den)` pair —
/// `(hits + 1) / (admitted + 2)` — so callers compare lines by integer
/// cross-multiplication (`num_i * den_j` vs `num_j * den_i`) without floating
/// point, matching the Lean mediant model. The `+1/+2` prior keeps every line's
/// weight strictly positive (no line is ever starved to zero — the sliver).
pub fn fano_line_weight(line: FanoLine) -> (u64, u64) {
    (fano_line_hits(line) + 1, fano_line_admitted(line) + 2)
}

/// %c of the predicted loser cache: each predicted hit pays zero compute, so it
/// rides the information front at 100% c (the photon); %c is therefore the
/// realized predicted hit rate. Rises toward 100 as the mycelial loop converges.
/// (`gnosis_engine_core::speed_of_light`.)
pub fn fano_router_speed_of_light_percent() -> f64 {
    let mut hits = 0u64;
    let mut admitted = 0u64;
    for i in 0..FANO_LINES {
        hits += LINE_HITS[i].load(Ordering::Relaxed);
        admitted += LINE_ADMITTED[i].load(Ordering::Relaxed);
    }
    if admitted == 0 {
        0.0
    } else {
        100.0 * hits as f64 / admitted as f64
    }
}

/// Clear the VentInterferePast feedback (tests / benches / a fresh epoch).
pub fn fano_router_reset() {
    for i in 0..FANO_LINES {
        LINE_ADMITTED[i].store(0, Ordering::Relaxed);
        LINE_HITS[i].store(0, Ordering::Relaxed);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Serializes the tests that touch the process-global feedback table so
    /// `cargo test`'s parallelism cannot interleave their resets.
    #[cfg(test)]
    static TEST_LOCK: std::sync::Mutex<()> = std::sync::Mutex::new(());

    #[test]
    fn test_fano_incidence() {
        assert!(fano_incidence(FanoPoint(0), FanoLine(0)));
        assert!(fano_incidence(FanoPoint(1), FanoLine(0)));
        assert!(!fano_incidence(FanoPoint(2), FanoLine(0)));
    }

    #[test]
    fn test_point_lines() {
        let lines = point_lines(FanoPoint(0));
        assert_eq!(lines.len(), 3); // Fano axiom: each point on 3 lines
    }

    #[test]
    fn test_line_points() {
        let points = line_points(FanoLine(0));
        assert_eq!(points.len(), 3); // Fano axiom: each line has 3 points
    }

    #[test]
    fn test_tier_coverage() {
        let e8_coverage = CacheTier::E8.coverage();
        assert_eq!(e8_coverage.len(), 7);

        let e6_coverage = CacheTier::E6.coverage();
        assert_eq!(e6_coverage.len(), 6);

        let e3_coverage = CacheTier::E3.coverage();
        assert_eq!(e3_coverage.len(), 3);
    }

    #[test]
    fn fold_routed_point_matches_division_routing() {
        // The Mersenne fold (Lean: FoilMersenneHotPath.fano_mod7_fold) is the
        // certified drop-in for `% 7` on multiplier-saturated ports: it must
        // route every hash to the same Fano point as the division form.
        let router = MycelialFanoRouter::new();
        let mut state = 0x5eed_u64;
        for _ in 0..10_000 {
            state = state
                .wrapping_mul(6364136223846793005)
                .wrapping_add(1442695040888963407);
            let folded = crate::foil_mersenne_hot_path::fano_point_of_hash(state);
            assert_eq!(folded as u64, state % 7);
            assert_eq!(router.route_query(state), router.route_query(state % 7));
        }
    }

    #[test]
    fn test_router_diversity() {
        let router = MycelialFanoRouter::new();
        let tiers = router.route_query(12345);
        assert!(tiers.len() > 0, "Every query should hit at least one tier");
    }

    #[test]
    fn test_mycelial_zero_deficit() {
        let router = MycelialFanoRouter::new();
        // All 7 possible Fano points should hit at least one tier
        for i in 0..7 {
            let tiers = router.route_query(i as u64);
            assert!(!tiers.is_empty(), "Fano point {} hits zero tiers", i);
        }
    }

    #[test]
    fn provenance_tag_roundtrips_through_low_bits() {
        for l in 0..7u8 {
            let line = FanoLine::new(l);
            // Arbitrary high entropy in the upper bits must survive untouched.
            let raw = 0xDEAD_BEEF_1234_5670u64;
            let tagged = tag_key_with_line(raw, line);
            assert_eq!(line_from_key(tagged).as_u8(), l, "line tag must round-trip");
            assert_eq!(tagged & !FANO_LINE_TAG_MASK, raw & !FANO_LINE_TAG_MASK,
                "tagging must only touch the low 3 provenance bits");
        }
    }

    #[test]
    fn weighted_plan_preserves_zero_deficit_and_total() {
        let _g = TEST_LOCK.lock().unwrap();
        fano_router_reset();
        let router = MycelialFanoRouter::new();
        // Across every Fano point, a discharge of >= 3 keeps all 3 incident
        // lines covered (>= 1 share each) and conserves the total.
        for q in 0..7u64 {
            let plan = router.weighted_discharge_plan(q, 30);
            assert_eq!(plan.len(), 3, "Fano point {q} must cover its 3 lines");
            assert_eq!(plan.iter().map(|(_, _, s)| *s).sum::<usize>(), 30);
            for (_, _, s) in &plan {
                assert!(*s >= 1, "zero-deficit: every incident line keeps a share");
            }
        }
    }

    #[test]
    fn vent_feedback_steers_discharge_toward_the_hitting_line() {
        let _g = TEST_LOCK.lock().unwrap();
        fano_router_reset();
        let router = MycelialFanoRouter::new();
        let q = 3u64;
        let lines = point_lines(FanoPoint::new((q % 7) as u8));
        let hot = lines[0];

        let share_of = |plan: &Vec<(FanoLine, CacheTier, usize)>, line: FanoLine| {
            plan.iter()
                .find(|(l, _, _)| l.as_u8() == line.as_u8())
                .map(|(_, _, s)| *s)
                .unwrap_or(0)
        };

        let before = router.weighted_discharge_plan(q, 30);

        // The hot line's forecasts keep landing; the other two are admitted but
        // never hit (topological debt). This is the realized-demand signal.
        for _ in 0..50 {
            fano_line_record_admit(hot);
            fano_line_credit_hit(hot);
        }
        for &cold in &lines[1..] {
            for _ in 0..50 {
                fano_line_record_admit(cold);
            }
        }

        let after = router.weighted_discharge_plan(q, 30);

        assert!(
            share_of(&after, hot) > share_of(&before, hot),
            "Hotelling reposition: the hitting line must gain discharge mass \
             (before={}, after={})",
            share_of(&before, hot),
            share_of(&after, hot),
        );
        assert_eq!(after.iter().map(|(_, _, s)| *s).sum::<usize>(), 30);
        // Cover is never lost even as the routing skews hard toward `hot`.
        for (_, _, s) in &after {
            assert!(*s >= 1, "zero-deficit preserved under skew");
        }
    }

    #[test]
    fn speed_of_light_percent_tracks_the_hit_rate() {
        let _g = TEST_LOCK.lock().unwrap();
        fano_router_reset();
        let line = FanoLine::new(0);
        for _ in 0..10 {
            fano_line_record_admit(line);
        }
        for _ in 0..6 {
            fano_line_credit_hit(line);
        }
        // 6 hits / 10 admitted = 60% c.
        assert!((fano_router_speed_of_light_percent() - 60.0).abs() < 1e-9);
        fano_router_reset();
        assert_eq!(fano_router_speed_of_light_percent(), 0.0, "empty cache is 0% c");
    }
}
